"""
StrokeGuard AI — HayMedics Academy
A branded stroke-risk screening tool (navy #1B2A6B / gold #F5A623).

Single file, self-contained: the HayMedics logo is embedded as base64 (no
separate image file to misplace), and the model trains itself from
stroke_data.csv on first load (so there is no saved-model version-mismatch
to break the deployment).
"""

import numpy as np
import pandas as pd
import streamlit as st

from sklearn.pipeline import Pipeline
from sklearn.compose import ColumnTransformer
from sklearn.preprocessing import FunctionTransformer, RobustScaler, OneHotEncoder
from sklearn.impute import SimpleImputer
from sklearn.linear_model import LogisticRegression
from sklearn.calibration import CalibratedClassifierCV
from sklearn.model_selection import train_test_split
from sklearn.metrics import confusion_matrix

