st.markdown(f"""
<div class="hm-header">
  <img src="data:image/png;base64,{LOGO_B64}" alt="HayMedics Academy"/>
  <span class="hm-pill">Clinical Decision Support</span>
</div>
<div class="hm-hero">
  <div class="hm-eyebrow">StrokeGuard AI</div>
  <h1>Stroke Risk <span class="accent">Screening</span></h1>
  <p>An evidence-based estimate of stroke risk from routine clinical inputs,
     calibrated and cost-weighted so a missed case is treated far more seriously
     than a false alarm.</p>
</div>
""", unsafe_allow_html=True)

# ----------------------------------------------------------------------
# Model (trains once)
# ----------------------------------------------------------------------
def add_features(X):
    X = X.copy()
    X["age_hypertension"] = X["age"] * X["hypertension"]
    X["age_heart_disease"] = X["age"] * X["heart_disease"]
    X["glucose_bmi"] = X["avg_glucose_level"] * X["bmi"]
    X["is_diabetic"] = (X["avg_glucose_level"] >= 126).astype(int)
    X["is_obese"] = (X["bmi"] >= 30).fillna(False).astype(int)
    X["is_elderly"] = (X["age"] >= 65).astype(int)
    X["vascular_risk_score"] = (X["hypertension"] + X["heart_disease"]
        + X["is_diabetic"] + X["is_obese"] + (X["age"] >= 55).astype(int))
    return X

@st.cache_resource
def load_model():
    df = pd.read_csv("stroke_data.csv").drop(columns=["id"])
    X, y = df.drop(columns=["stroke"]), df["stroke"]
    X_tr, X_val, y_tr, y_val = train_test_split(X, y, test_size=.20,
                                                stratify=y, random_state=SEED)
    cont = ["age","avg_glucose_level","bmi","age_hypertension",
            "age_heart_disease","glucose_bmi","vascular_risk_score"]
    binr = ["hypertension","heart_disease","is_diabetic","is_obese","is_elderly"]
    cat  = ["gender","ever_married","work_type","Residence_type","smoking_status"]
    prep = ColumnTransformer([
        ("num", Pipeline([("i",SimpleImputer(strategy="median")),("s",RobustScaler())]), cont),
        ("bin", SimpleImputer(strategy="most_frequent"), binr),
        ("cat", Pipeline([("i",SimpleImputer(strategy="most_frequent")),
                          ("o",OneHotEncoder(handle_unknown="ignore",sparse_output=False))]), cat),
    ])
    pipe = Pipeline([("e",FunctionTransformer(add_features)),("p",prep),
                     ("m",LogisticRegression(max_iter=2000,class_weight="balanced",random_state=SEED))])
    model = CalibratedClassifierCV(pipe, method="sigmoid", cv=3).fit(X_tr, y_tr)
    p = model.predict_proba(X_val)[:,1]
    bt, bc = .5, 1e18
    for t in np.linspace(.01,.99,99):
        tn,fp,fn,tp = confusion_matrix(y_val,(p>=t).astype(int),labels=[0,1]).ravel()
        c = 10*fn + fp
        if c < bc: bc, bt = c, t
    return model, float(bt)

with st.spinner("Preparing the model (first load only)…"):
    model, THRESHOLD = load_model()

# ----------------------------------------------------------------------
# Patient assessment card
# ----------------------------------------------------------------------
with st.container(border=True):
    st.markdown('<div class="hm-cardtitle">Patient Assessment</div>', unsafe_allow_html=True)
    st.markdown('<div class="hm-sub">Enter the patient\'s details, then run the screening.</div>',
                unsafe_allow_html=True)
    c1, c2 = st.columns(2, gap="large")
    with c1:
        gender = st.selectbox("Gender", ["Male","Female","Other"])
        age = st.slider("Age", 1, 100, 55)
        hypertension = 1 if st.radio("Hypertension", ["No","Yes"], horizontal=True)=="Yes" else 0
        heart_disease = 1 if st.radio("Heart disease", ["No","Yes"], horizontal=True)=="Yes" else 0
        ever_married = st.radio("Ever married", ["Yes","No"], horizontal=True)
    with c2:
        work_type = st.selectbox("Work type",
                                 ["Private","Self-employed","Govt_job","children","Never_worked"])
        residence = st.radio("Residence", ["Urban","Rural"], horizontal=True)
        glucose = st.number_input("Average glucose (mg/dL)", 40.0, 350.0, 105.0, step=1.0)
        bmi = st.number_input("BMI (kg/m²)", 10.0, 60.0, 27.0, step=0.1)
        smoking = st.selectbox("Smoking status",
                               ["never smoked","formerly smoked","smokes","Unknown"])
    go = st.button("Run stroke screening")

# ----------------------------------------------------------------------
# Result card with custom SVG gauge
# ----------------------------------------------------------------------
if go:
    patient = pd.DataFrame([{
        "gender":gender,"age":age,"hypertension":hypertension,"heart_disease":heart_disease,
        "ever_married":ever_married,"work_type":work_type,"Residence_type":residence,
        "avg_glucose_level":glucose,"bmi":bmi,"smoking_status":smoking}])
    risk = float(model.predict_proba(patient)[0,1])
    hi = risk >= THRESHOLD
    color = GOLD if hi else GREEN
    badge = ('<span class="hm-badge hi">Elevated risk</span>' if hi
             else '<span class="hm-badge lo">Lower risk</span>')
    msg = ("Above the screening threshold — recommend clinical review."
           if hi else "Below the screening threshold — routine follow-up.")

    r = 78; import math; C = 2*math.pi*r
    frac = max(min(risk, 1.0), 0.0)
    offset = C*(1-frac)

    with st.container(border=True):
        st.markdown('<div class="hm-cardtitle">Screening Result</div>', unsafe_allow_html=True)
        st.markdown(f"""
        <div class="hm-result">
          <svg width="200" height="200" viewBox="0 0 200 200">
            <circle cx="100" cy="100" r="{r}" fill="none" stroke="#eef1f7" stroke-width="18"/>
            <circle cx="100" cy="100" r="{r}" fill="none" stroke="{color}" stroke-width="18"
                    stroke-linecap="round" stroke-dasharray="{C:.1f}" stroke-dashoffset="{offset:.1f}"
                    transform="rotate(-90 100 100)"/>
            <text x="100" y="92" text-anchor="middle" font-family="Fraunces,serif"
                  font-size="40" font-weight="600" fill="{NAVY}">{risk*100:.1f}%</text>
            <text x="100" y="118" text-anchor="middle" font-family="Plus Jakarta Sans,sans-serif"
                  font-size="13" fill="#5b6479">estimated risk</text>
          </svg>
          <div class="hm-readout">
            {badge}
            <h3>{'Recommend review' if hi else 'No flag raised'}</h3>
            <p>{msg}</p>
            <p style="margin-top:.5rem; font-size:.82rem;">Screening threshold:
               <b>{THRESHOLD*100:.0f}%</b> · weighted to catch true cases.</p>
          </div>
        </div>
        """, unsafe_allow_html=True)
        st.caption("Screening estimate only — not a diagnosis. Final decisions rest "
                   "with the clinician, informed by examination, history and investigations.")

